// parseSearchScopes normalizes a comma-separated --in value into resource_type
// names matching the local store. "kb" is an alias for "solutions".
func parseSearchScopes(in string) []string {
	in = strings.TrimSpace(in)
	if in == "" {
		return nil
	}
	var out []string
	for _, p := range strings.Split(in, ",") {
		p = strings.TrimSpace(strings.ToLower(p))
		if p == "" {
			continue
		}
		if p == "kb" || p == "solution" {
			p = "solutions"
		}
		out = append(out, p)
	}
	return out
}

// searchInScopes runs a LIKE-based scan over the resources table for each
// requested resource type. Falls back to LIKE because the generic FTS5 table
// doesn't carry resource_type filtering.
func searchInScopes(db *store.Store, scopes []string, query string, limit int) ([]json.RawMessage, error) {
	q := "%" + strings.ToLower(query) + "%"
	var out []json.RawMessage
	for _, scope := range scopes {
		rows, err := db.Query(
			`SELECT data FROM resources WHERE resource_type = ? AND lower(data) LIKE ? LIMIT ?`,
			scope, q, limit,
		)
		if err != nil {
			return nil, err
		}
		for rows.Next() {
			var raw []byte
			if err := rows.Scan(&raw); err != nil {
				continue
			}
			out = append(out, json.RawMessage(append([]byte(nil), raw...)))
		}
		rows.Close()
		if len(out) >= limit {
			break
		}
	}
	if len(out) > limit {
		out = out[:limit]
	}
	return out, nil
}

